"tenant_id" int8 NOT NULL DEFAULT 1,
"dept_id" int8 NOT NULL DEFAULT 1,
"name" varchar(50)  NOT NULL,
"category_id" int8 NOT NULL,
"device_type" int2 NOT NULL,
"img_url" varchar(400) ,
"cp_id" int8 NOT NULL,
"tp_id" int8 NOT NULL,
"remark" varchar(400)
)
;
COMMENT ON COLUMN "public"."iot_product"."id" IS 'ID';
